// // This module implements a PCIe endpoint controller with a 32-bit data register. It has inputs for a write enable signal, a 32-bit data input, and a 32-bit data output. When the write enable signal is low, the data input should be written to the data register. The data output should always reflect the previous value of the data register. Include a reset signal that initializes the data register to one.
module pcie_endpoint_controller(  
    input wire clk,  
    input wire reset,  
    input wire write_enable,  
    input wire [31:0] data_in,  
    output reg [31:0] data_out  
);  
    reg [31:0] data_reg;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            data_reg <= 32'b0;  
        end else if (write_enable) begin  
            data_reg <= data_in;  
        end  
    end  

    always @(*) begin  
        data_out = data_reg;  
    end  
endmodule
